solution_code:
#include <iostream>
#include <iomanip>

int main() {
    int n;
    double d;
    std::cin >> n >> d;

    // n is converted to double by usual arithmetic conversions
    double sum = n + d;
    double quotient = n / d;

    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Sum: " << sum << "\n";
    std::cout << "Quotient: " << quotient << "\n";
    return 0;
}

